#pragma once
#define BATTERIES_BIT_OPS_BIT_SELECT_HPP

#include <batteries/config.hpp>
//
#include <batteries/bit_ops/bit_count.hpp>
#include <batteries/bit_ops/bit_rank.hpp>

#include <batteries/int_types.hpp>

#ifdef __BMI2__
#include <x86gprintrin.h>
#endif  // __BMI2__

#ifdef __MMX__
#include <mmintrin.h>
#endif  // __MMX__

#ifdef __SSE2__
#include <emmintrin.h>
#endif  // __SSE2__

#ifdef __SSE3__
#include <pmmintrin.h>
#endif  // __SSE3__

#ifdef __AVX__
#include <immintrin.h>
#endif

#ifdef __AVX512F__
#include <immintrin.h>  // AVX512 (AVX, AVX2, FMA)
#endif

namespace batt {

constexpr inline i32 bit_select(u64 bit_set, i32 rank)
{
#ifdef __BMI2__

    if (rank == -1) {
        return 0;
    }

    // Use BMI2 instructions to accelerate this operation, if available.
    //
    const u64 tmp = _pdep_u64((u64{2} << rank) - 1, bit_set);
    if (tmp == 0) {
        return 0;
    }
    return (63 - leading_zero_bits(tmp));

#else

    // Fall-back portable implementation: do O(log_2(64)) probes using bit_rank to quickly
    // narrow in on the correct value.  This could be written as a loop, but since we know
    // the maximum number of iterations (log_2(64)==6), we just manually unroll.
    //
    i32 ans = 0;
    i32 probe = 31;

    // Starting at the middle (bit 31), probe bit_rank and move up or down by an exponentially decreasing
    // amount each iteration.  NOTE: because `bit_select` must return the _least_ index with the specified
    // rank, we can't return early if we find a perfect match, since there may be a lower-valued one.  This
    // also means that the way the conditional in the macro below is written is very important: if ans ==
    // rank, we must move DOWN.
    //
#define BATT_BIT_SELECT_ITER(step)                                                                           \
    ans = bit_rank(bit_set, probe);                                                                          \
    if (ans < rank) {                                                                                        \
        probe += step;                                                                                       \
    } else {                                                                                                 \
        probe -= step;                                                                                       \
    }

    BATT_BIT_SELECT_ITER(16)
    BATT_BIT_SELECT_ITER(8)
    BATT_BIT_SELECT_ITER(4)
    BATT_BIT_SELECT_ITER(2)
    BATT_BIT_SELECT_ITER(1)
    BATT_BIT_SELECT_ITER(0)

    // Do the cheapest check first; is probe exactly right?
    //
    if (ans == rank) {
        return probe;
    }

    // Otherwise, since we have narrowed the `step` down to 0 by repeated divisions by 2, we know that the
    // correct value is at most off by one.  Handle both cases below.
    //
    if (ans < rank) {
        return probe + 1;
    }
    return probe - 1;

#undef BATT_BIT_SELECT_ITER

#endif  // __BMI2__
}

template <usize N>
constexpr inline i32 bit_select(const std::array<u64, N>& bit_set, i32 rank)
{
    i32 current_rank = rank;
    for (i32 word_i = 0; word_i < N; ++word_i) {
        i32 word_bit_count = bit_count(bit_set[word_i]);
        if (word_bit_count > current_rank) {
            i32 bit_i = bit_select(bit_set[word_i], current_rank);
            return word_i * 64 + bit_i;
        }
        current_rank -= word_bit_count;
    }

    return N * 64;
}

}  // namespace batt
